{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the effective Rydberg energy based on the observed 1s exciton binding energy and then applying the Rydberg formula for the n=3 state, paying close attention to the sign convention of binding energy.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (Ry*) using the relationship between the band gap (Eg) and the 1s exciton peak energy (E_ex). Note that the binding energy (Eb) is defined as Eg minus E_ex. Use the hydrogenic model relation Eb = Ry* / (n^2) where n=1 to find Ry*."
    },
    {
      "label": "helper_2",
      "instructions": "Using the Ry* value obtained from the first step, calculate the energy level for the n=3 state using the formula E_n = -Ry* / (n^2). Ensure the final answer reflects the correct sign convention for a bound state energy relative to the band edge."
    }
  ],
  "synthesis_brief": "Combine the calculated Ry* from helper 1 with the n=3 formula in helper 2 to provide the final energy value, ensuring the sign is consistent with the Rydberg energy convention for bound states."
}

